"use strict";(()=>{const t=()=>{if(window.matchMedia("(pointer: coarse)").matches||window.matchMedia("(prefers-reduced-motion: reduce)").matches)return;const n=document.querySelectorAll(".glass-panel");if(n.length===0)return;let o=-9999,r=-9999;const s=()=>{for(const e of n){const c=e.getBoundingClientRect();e.style.setProperty("--glow-x",`${o-c.left}px`),e.style.setProperty("--glow-y",`${r-c.top}px`)}};document.addEventListener("mousemove",e=>{o=e.clientX,r=e.clientY,s()}),document.addEventListener("scroll",s,{capture:!0,passive:!0})};document.readyState==="loading"?document.addEventListener("DOMContentLoaded",t):t()})();
